1114 /// Fold a divide or remainder with a select instruction divisor when one of the
1115 /// select operands is zero. In that case, we can use the other select operand
1116 /// because div/rem by zero is undefined.
1117 bool InstCombinerImpl::simplifyDivRemOfSelectWithZeroOp(BinaryOperator &I) {
1118   SelectInst *SI = dyn_cast<SelectInst>(I.getOperand(1));
1119   if (!SI)
1120     return false;
1121 
1122   int NonNullOperand;
1123   if (match(SI->getTrueValue(), m_Zero()))
1124     // div/rem X, (Cond ? 0 : Y) -> div/rem X, Y
1125     NonNullOperand = 2;
1126   else if (match(SI->getFalseValue(), m_Zero()))
1127     // div/rem X, (Cond ? Y : 0) -> div/rem X, Y
1128     NonNullOperand = 1;
1129   else
1130     return false;
1131 
1132   // Change the div/rem to use 'Y' instead of the select.
1133   replaceOperand(I, 1, SI->getOperand(NonNullOperand));
1134 
1135   // Okay, we know we replace the operand of the div/rem with 'Y' with no
1136   // problem.  However, the select, or the condition of the select may have
1137   // multiple uses.  Based on our knowledge that the operand must be non-zero,
1138   // propagate the known value for the select into other uses of it, and
1139   // propagate a known value of the condition into its other users.
1140 
1141   // If the select and condition only have a single use, don't bother with this,
1142   // early exit.
1143   Value *SelectCond = SI->getCondition();
1144   if (SI->use_empty() && SelectCond->hasOneUse())
1145     return true;
1146 
1147   // Scan the current block backward, looking for other uses of SI.
1148   BasicBlock::iterator BBI = I.getIterator(), BBFront = I.getParent()->begin();
1149   Type *CondTy = SelectCond->getType();
1150   while (BBI != BBFront) {
1151     --BBI;
1152     // If we found an instruction that we can't assume will return, so
1153     // information from below it cannot be propagated above it.
1154     if (!isGuaranteedToTransferExecutionToSuccessor(&*BBI))
1155       break;
1156 
1157     // Replace uses of the select or its condition with the known values.
1158     for (Use &Op : BBI->operands()) {
1159       if (Op == SI) {
1160         replaceUse(Op, SI->getOperand(NonNullOperand));
1161         Worklist.push(&*BBI);
1162       } else if (Op == SelectCond) {
1163         replaceUse(Op, NonNullOperand == 1 ? ConstantInt::getTrue(CondTy)
1164                                            : ConstantInt::getFalse(CondTy));
1165         Worklist.push(&*BBI);
1166       }
1167     }
1168 
1169     // If we past the instruction, quit looking for it.
1170     if (&*BBI == SI)
1171       SI = nullptr;
1172     if (&*BBI == SelectCond)
1173       SelectCond = nullptr;
1174 
1175     // If we ran out of things to eliminate, break out of the loop.
1176     if (!SelectCond && !SI)
1177       break;
1178 
1179   }
1180   return true;
1181 }
