1245   // With appropriate no-wrap constraints, remove a common factor in the
1246   // dividend and divisor that is disguised as a left-shift amount.
1247   if (match(Op0, m_Shl(m_Value(X), m_Value(Z))) &&
1248       match(Op1, m_Shl(m_Value(Y), m_Specific(Z)))) {
1249     auto *Shl0 = cast<OverflowingBinaryOperator>(Op0);
1250     auto *Shl1 = cast<OverflowingBinaryOperator>(Op1);
1251 
1252     // For unsigned div, we need 'nuw' on both shifts or
1253     // 'nsw' on both shifts + 'nuw' on the dividend.
1254     // (X << Z) / (Y << Z) --> X / Y
