1260 
1261     // For signed div, we need 'nsw' on both shifts + 'nuw' on the divisor.
1262     // (X << Z) / (Y << Z) --> X / Y
1263     if (IsSigned && Shl0->hasNoSignedWrap() && Shl1->hasNoSignedWrap() &&
